SELECT file_path, file_size
FROM media_assets
WHERE file_size > 50 AND upload_date >= DATE('now', '-30 days');

SELECT media_id, SUM(view_count) AS total_views
FROM media_metadata
GROUP BY media_id;

SELECT SUM(share_count) AS total_shares
FROM media_shares
WHERE media_id = 1 AND platform_id = 1;

SELECT media_id
FROM media_metadata
WHERE view_count = (SELECT MAX(view_count) FROM media_metadata);

SELECT platform_name
FROM social_media_platforms
WHERE platform_id = 0;

SELECT file_path
FROM media_assets
WHERE file_size = (SELECT MAX(file_size) FROM media_assets);
